// Script Continued Below
function onChange(control, oldValue, newValue, isLoading, isTemplate) {
	if (isLoading || newValue === '') {
		return;
	}


	// STRY0050440 
	g_form.clearValue('is_global_tasking_authority');
	g_form.clearValue('is_tasker_application_admin');
	g_form.clearValue('user_is_organization_admin');
	g_form.clearValue('can_manage_process_permissions');
	g_form.clearValue('can_manage_global_processes');
	g_form.clearValue('has_personal_process_rights');
	g_form.clearValue('u_isdefaultou');

	var member_user = g_form.getValue('office_member');
	var OUPermissions  = new GlideAjax('ClientUserInfoScripts');
	OUPermissions.addParam('sysparm_name','userHasRole');
	OUPermissions.addParam("user", member_user);
	OUPermissions.addParam("roles",
	['x_153465_discovert.tasker_global_Tasking_Authority_member_admin',
	'x_153465_discovert.tasker_application_admin',
	'x_153465_discovert.tasker_organizational_admin',
	'x_153465_discovert.tasker_process_template_admin',
	'x_153465_discovert.tasker_process_template_global',
	'x_153465_discovert.tasker_process_template_user',
	'admin'
	]);
	OUPermissions.getXML(f_returnUserHasRole);
	function f_returnUserHasRole(response){
		var answer = response.responseXML.documentElement.getAttribute("answer");
		var permissions = JSON.parse(answer);
		for(var i=0; i<permissions.length; i++){
			switch (i) {
				case 0:
				g_form.setValue('is_global_tasking_authority', permissions[i].hasRole);
				break;
				case 1:
				g_form.setValue('is_tasker_application_admin', permissions[i].hasRole);
				break;
				case 2:
				g_form.setValue('user_is_organization_admin',  permissions[i].hasRole);
				break;
				case 3:
				g_form.setValue('can_manage_process_permissions', permissions[i].hasRole);
				break;
				case 4:
				g_form.setValue('can_manage_global_processes', permissions[i].hasRole);
				break;
				case 5:
				g_form.setValue('has_personal_process_rights', permissions[i].hasRole);
				break;
			}
		}
	}
}
